  function getListContacts(list){var fc=cls.filter(function(c){if(list.fCountry&&list.fCountry.length>0&&list.fCountry.indexOf(c.country)<0)return false;if(list.fType&&list.fType.length>0&&list.fType.indexOf(c.type)<0)return false;if(list.fStatus&&list.fStatus.length>0&&list.fStatus.indexOf(c.status)<0)return false;if(list.fVehicle&&list.fVehicle.length>0){var has=false;(c.vehicles||[]).forEach(function(v){if(list.fVehicle.indexOf(v)>=0)has=true;});if(!has)return false;}if(list.fTemp&&list.fTemp.length>0&&list.fTemp.indexOf(c.temp)<0)return false;if(list.fPrio&&list.fPrio.length>0&&list.fPrio.indexOf(c.priority)<0)return false;if(list.fSales&&list.fSales.length>0&&list.fSales.indexOf(c.sales)<0)return false;return true;});var res=[];fc.forEach(function(cl2){var mc=ctsOf(cl2.id);if(list.primaryOnly){mc=mc.filter(function(ct2){return ct2.primary;});}if(list.fBadge&&list.fBadge.length>0){if(list.fBadge.indexOf("bloomberg")>=0)mc=mc.filter(function(ct2){return ct2.bloomberg;});if(list.fBadge.indexOf("fostPres")>=0)mc=mc.filter(function(ct2){return ct2.fostPres;});if(list.fBadge.indexOf("vdr")>=0)mc=mc.filter(function(ct2){return ct2.vdr;});}mc.forEach(function(ct2){if(ct2.email)res.push({ct:ct2,cl:cl2});});});return res;}

